	uf := &UnionFind{
		parent:    make([]int64, size),
		rank:      make([]int64, size),
		components: size,
	}
	for i := int64(0); i < size; i++ {
		uf.parent[i] = i
		uf.rank[i] = 1
	}
	return uf
}

func (uf *UnionFind) Find(x int64) int64 {
	if uf.parent[x] != x {
		uf.parent[x] = uf.Find(uf.parent[x])
	}
	return uf.parent[x]
}

func (uf *UnionFind) Union(x, y int64) bool {
	rootX := uf.Find(x)
	rootY := uf.Find(y)
	if rootX == rootY {
		return false
	}
	if uf.rank[rootX] > uf.rank[rootY] {
		uf.parent[rootY] = rootX
		uf.rank[rootX] += uf.rank[rootY]
	} else {
		uf.parent[rootX] = rootY
		uf.rank[rootY] += uf.rank[rootX]
	}
	uf.components--
	return true
}

func (uf *UnionFind) GetComponents() int64 {
	return uf.components
}

func solve(n int64, edges [][]int64, k int64) int64 {
	if k > n {
		return -1
	}
	if k == n {
		return 0
	}
	if len(edges) == 0 {
		return 0
	}

	// Sort edges by time in ascending order
	sortedEdges := make([][]int64, len(edges))
	copy(sortedEdges, edges)
	for i := 0; i < len(sortedEdges); i++ {
		for j := i + 1; j < len(sortedEdges); j++ {
			if sortedEdges[i][2] > sortedEdges[j][2] {
				sortedEdges[i], sortedEdges[j] = sortedEdges[j], sortedEdges[i]
			}
		}
	}

