	right := sortedEdges[len(sortedEdges)-1][2]
	result := right

	check := func(t int64) bool {
		uf := NewUnionFind(n)
		for _, edge := range sortedEdges {
			if edge[2] > t {
				uf.Union(edge[0], edge[1])
			}
		}
		return uf.GetComponents() >= k
	}

	if check(0) {
		return 0
	}

	for left <= right {
		mid := (left + right) / 2
		if check(mid) {
			result = mid
			right = mid - 1
		} else {
			left = mid + 1
		}
	}

	return result
}
